 output EndofScore; 
 parameter DataLength=4; 
 input [DataLength-1:0] KeyOutput; 
 parameter AddressBits=5; 
 input [AddressBits-1:0] StartAddress; 
 output reg [AddressBits-1:0] CurrentAddress; 
