module rtlpp_06708 (
    address,
    byteenable,
    chipselect,
    clk,
    clken,
    freeze,
    reset,
    reset_req,
    write,
    writedata,
    readdata
);

  parameter INIT_FILE = "mon_sopc_ram.hex";

  output [31:0] readdata;
  input [12:0] address;
  input [3:0] byteenable;
  input chipselect;
  input clk;
  input clken;
  input freeze;
  input reset;
  input reset_req;
  input write;
  input [31:0] writedata;

  reg [31:0] memory[0:5119];
  reg [31:0] readdata_reg;
  wire clocken0;
  wire wren;

  assign wren = chipselect & write;
  assign clocken0 = clken & ~reset_req;

  // Initial memory content if INIT_FILE is specified
  initial begin
      $readmemh(INIT_FILE, memory);
  end

  always @(posedge clk) begin
    if (clocken0) begin
      if (wren) begin
        if (byteenable[0]) memory[address][7:0] <= writedata[7:0];
        if (byteenable[1]) memory[address][15:8] <= writedata[15:8];
        if (byteenable[2]) memory[address][23:16] <= writedata[23:16];
        if (byteenable[3]) memory[address][31:24] <= writedata[31:24];
      end
      readdata_reg <= memory[address];
    end
  end

  assign readdata = readdata_reg;

endmodule

