    if (advanced_sw == 1 && ((VGA_VERT_COORD == (1024 - yadjust2) || VGA_VERT_COORD == (1024 - yadjust2 - 1024/scale2)) && (VGA_HORZ_COORD >= xadjust2 && VGA_HORZ_COORD <= (xadjust2 + 1280/scale2))))
