      START: begin

          txd <= 1'b0;
          if( state_cntr[7:0] != '0 ) begin
            // holding start bits
            state_cntr[7:0]--;
          end else begin
            // transition
            state_cntr[7:0] <= DATA_BITS - 1'b1;
            tx_state <= tx_state.next();
          end // state_cntr

      end
      DATA: begin

          // setting data, MSB first
          txd <= tx_data_buf[state_cntr[7:0]];

          if( state_cntr[7:0] != '0 ) begin
            state_cntr[7:0]--;
          end else begin
            // transition
            state_cntr[7:0] <= STOP_BITS - 1'b1;
            tx_state <= tx_state.next();
          end // state_cntr

      end
    endcase // tx_state

  end
end

