module rtlpp_04547 (
    serial_in,
    data_out,
    read_buffer,
    reset_buffer,
    en_16_x_baud,
    buffer_data_present,
    buffer_full,
    buffer_half_full,
    clk
);

input serial_in;
output [7:0] data_out;
input read_buffer;
input reset_buffer;
input en_16_x_baud;
output buffer_data_present;
output buffer_full;
output buffer_half_full;
input clk;

wire serial_in;
wire [7:0] data_out;
wire read_buffer;
wire reset_buffer;
wire en_16_x_baud;
wire buffer_data_present;
wire buffer_full;
wire buffer_half_full;
wire clk;

wire [7:0] uart_data_out;
wire fifo_write;

// Embedded logic for kcuart_rx
reg [7:0] shift_reg;
reg [3:0] bit_counter;
reg data_strobe;

always @(posedge clk or posedge en_16_x_baud) begin
    if (en_16_x_baud) begin
        bit_counter <= 0;
        data_strobe <= 0;
    end else if (serial_in == 1'b0 && bit_counter == 0) begin
        bit_counter <= bit_counter + 1;
    end else if (bit_counter != 0 && bit_counter < 10) begin
        shift_reg <= {serial_in, shift_reg[7:1]};
        bit_counter <= bit_counter + 1;
    end else if (bit_counter == 10) begin
        bit_counter <= 0;
        data_strobe <= 1;
    end else begin
        data_strobe <= 0;
    end
end

assign uart_data_out = shift_reg;
assign fifo_write = data_strobe;

// Embedded logic for bbfifo_16x8
reg [7:0] fifo_mem [15:0];
reg [3:0] write_pointer, read_pointer, count;
reg buffer_data_present, buffer_full, buffer_half_full;

always @(posedge clk or posedge reset_buffer) begin
    if (reset_buffer) begin
        write_pointer <= 0;
        read_pointer <= 0;
        count <= 0;
    end else begin
        if (fifo_write && count < 16) begin
            fifo_mem[write_pointer] <= uart_data_out;
            write_pointer <= write_pointer + 1;
            count <= count + 1;
        end

        if (read_buffer && count > 0) begin
            read_pointer <= read_pointer + 1;
            count <= count - 1;
        end

        buffer_data_present <= (count > 0);
        buffer_full <= (count == 16);
        buffer_half_full <= (count >= 8);
    end
end

assign data_out = fifo_mem[read_pointer];

endmodule

