    input [3:0] Present_State,
    output reg [3:0] Next_State
);

always @(*) begin
    case (Present_State)
        4'b1111: begin
            if (Input == 2'b10) begin
                Next_State = 4'b0100;
            end else if (Input == 2'b01) begin
                Next_State = 4'b0000;
            end else begin
                Next_State = 4'b1111;
            end
        end
        4'b0100: begin
            if (Input == 2'b10) begin
                Next_State = 4'b0001;
            end else if (Input == 2'b01) begin
