            if (Input == 2'b10) begin
                Next_State = 4'b0010;
            end else if (Input == 2'b01) begin
                Next_State = 4'b0110;
            end else begin
                Next_State = 4'b1111;
            end
        end
        4'b0110: begin
            if (Input == 2'b10) begin
                Next_State = 4'b0111;
            end else if (Input == 2'b01) begin
                Next_State = 4'b0011;
            end else begin
                Next_State = 4'b1111;
            end
        end
        4'b0111: begin
            if (Input == 2'b10 || Input == 2'b01) begin
                Next_State = 4'b0111;
            end else begin
                Next_State = 4'b1111;
            end
        end
        4'b0000: begin
            if (Input == 2'b10 || Input == 2'b01) begin
                Next_State = 4'b0001;
            end else begin
                Next_State = 4'b1111;
            end
        end
        4'b0001: begin
            if (Input == 2'b10 || Input == 2'b01) begin
                Next_State = 4'b0010;
            end else begin
                Next_State = 4'b1111;
            end
        end
        4'b0010: begin
