module rtlpp_02500(
    input wire clk,
    input wire [1:0] ct,
    input wire rst,
    input wire [15:0] a,
    output reg [7:0] dout,
    input wire [7:0] din,
    input wire rd,
    input wire wr,
    output reg int_tim_req,
    input wire int_tim_ack
    );

    reg [7:0] reg_div;
    reg [7:0] reg_tima;
    reg [7:0] reg_tma;
    reg [7:0] reg_tac;

    wire addr_in_timer = (a == 16'hFF04) ||
                         (a == 16'hFF05) ||
                         (a == 16'hFF06) ||
                         (a == 16'hFF07);

    reg [15:0] div;

    wire reg_timer_enable = reg_tac[2];
    wire [1:0] reg_clock_sel = reg_tac[1:0];

    assign reg_div = div[15:8];
    wire clk_4khz = div[9];
    wire clk_256khz = div[3];
    wire clk_64khz = div[5];
    wire clk_16khz = div[7];
    wire clk_tim;
    assign clk_tim = reg_timer_enable ? (
        (reg_clock_sel == 2'b00) ? clk_4khz : (
        (reg_clock_sel == 2'b01) ? clk_256khz : (
        (reg_clock_sel == 2'b10) ? clk_64khz :
                                   clk_16khz))) : 1'b0;

    reg last_clk_tim;
    reg write_block;

    always @(*) begin
        dout = 8'hFF;
        case (a)
            16'hFF04: dout = reg_div;
            16'hFF05: dout = reg_tima;
            16'hFF06: dout = reg_tma;
            16'hFF07: dout = reg_tac;
        endcase
    end

    always @(posedge clk) begin
        last_clk_tim <= clk_tim;
    end

    always @(posedge clk) begin
        if (rst) begin
            reg_tima <= 0;
            reg_tma <= 0;
            reg_tac <= 0;
            div <= 0;
            int_tim_req <= 0;
            write_block <= 0;
        end else begin
            div <= div + 1'b1;
            if (wr && a == 16'hFF04) 
                div <= 4;
