    output reg IfBeq,
    output reg [1:0] ExtOp,
    output reg [1:0] ALUOp,
    output reg jr,
    output reg jal
);

    always @(*) begin
        // Default values
        RegDst = 2'b00;
        ALUSrc = 1'b0;
        MemtoReg = 2'b00;
        RegWrite = 1'b0;
        MemRead = 1'b0;
        MemWrite = 1'b0;
        IfBeq = 1'b0;
        ExtOp = 2'b00;
        ALUOp = 2'b00;
        jr = 1'b0;
        jal = 1'b0;

        case(op)
            6'b000000: begin // R-type instructions
                RegDst = 2'b01;
                RegWrite = 1'b1;
                ALUOp = 2'b10;
                if (func == 6'b001000) begin // jr instruction
                    jr = 1'b1;
                    RegWrite = 1'b0;
                end
