            6'b100011: begin // lw
                ALUSrc = 1'b1;
                MemtoReg = 2'b01;
                RegWrite = 1'b1;
                MemRead = 1'b1;
                ExtOp = 2'b01;
            end
            6'b101011: begin // sw
                ALUSrc = 1'b1;
                MemWrite = 1'b1;
                ExtOp = 2'b01;
            end
            6'b000100: begin // beq
                IfBeq = 1'b1;
                ALUOp = 2'b01;
                ExtOp = 2'b01;
            end
            6'b001000: begin // addi
                ALUSrc = 1'b1;
                RegWrite = 1'b1;
                ExtOp = 2'b01;
            end
            6'b001100: begin // andi
                ALUSrc = 1'b1;
                RegWrite = 1'b1;
                ALUOp = 2'b11;
