            6'b001101: begin // ori
                ALUSrc = 1'b1;
                RegWrite = 1'b1;
                ALUOp = 2'b11;
            end
            6'b001010: begin // slti
                ALUSrc = 1'b1;
                RegWrite = 1'b1;
                ALUOp = 2'b11;
                ExtOp = 2'b01;
            end
            6'b000010: begin // j
