module autovcoder_099702 (
    input  [15:0] x,
    input  [15:0] y,
    output [31:0] p
);

  // Generate abs values
  wire [15:0] x_abs;
  wire [15:0] y_abs;

  wire x_sign;
  wire y_sign;

  assign x_sign = x[15];
  assign y_sign = y[15];


  sec_complement_w16 abs_X (
      .data_in(x),
      .sign(x[15]),
      .data_out(x_abs)
  );

  // Going for Y_abs


  sec_complement_w16 abs_Y (
      .data_in(y),
      .sign(y[15]),
      .data_out(y_abs)
  );

  // Rounding X

  wire [15:0] x_round;
  rounding_mod RoundX (
      x_abs,
      x_round
  );

  // Rounding Y 

  wire [15:0] y_round;
  rounding_mod RoundY (
      y_abs,
      y_round
  );

  // encode the round value x_abs
  wire [3:0] x_enc;
  PriorityEncoder_16 EncX (
      x_round,
      x_enc
  );

  // encode the round value y_abs
  wire [3:0] y_enc;
  PriorityEncoder_16 EncY (
      y_round,
      y_enc
  );

  // Shift Xr * Y_abs
  wire [31:0] xr_Y;
  Barrel32L XRtimesY (
      y_abs,
      x_enc,
      xr_Y
  );

  // Shift Yr * x_abs
  wire [31:0] yr_X;
  Barrel32L YRtimesX (
      x_abs,
      y_enc,
      yr_X
  );

  // Shift Yr * Xr
  wire [31:0] yr_yx;
  Barrel32L YRtimesXR (
      x_round,
      y_enc,
      yr_yx
  );

  // sum xr_Y yr_X

  wire [31:0] P;

  assign P = xr_Y + yr_X;


  // difference to get absolute value of product

  wire [31:0] prod_abs;
  wire [31:0] Z;

  assign Z = yr_yx;
  wire [31:0] tmp;
  wire [31:0] tmp1;
  wire [31:0] tmp2;

  assign tmp = (P ^ Z);
  assign tmp1 = (P << 1);
  assign tmp2 = (P & Z) << 1;
  //assign prod_abs = (P ^ Z) & (((P << 1) ^ (P ^ Z)) | (( P & Z) << 1));
  assign prod_abs = tmp & ((tmp1 ^ tmp) | tmp2);
  // Revert to the signed value


  wire prod_sign;

  assign prod_sign = x_sign ^ y_sign;

  sec_complement_w32 sign_P (
      .data_in(prod_abs),
      .sign(prod_sign),
      .data_out(p)
  );


endmodule

