    output wire reset,
    output reg [DATA_WIDTH-1:0] data_reg,
    output reg data_reg_valid,
    output reg [3:0] inst_reg,
    output reg inst_reg_valid
);

    // Internal signals
    reg [3:0] current_state, next_state;

    // State encoding
    localparam [3:0]
        TEST_LOGIC_RESET = 4'h0,
        RUN_TEST_IDLE    = 4'h1,
        SELECT_DR_SCAN   = 4'h2,
        CAPTURE_DR       = 4'h3,
        SHIFT_DR         = 4'h4,
        EXIT1_DR         = 4'h5,
        PAUSE_DR         = 4'h6,
        EXIT2_DR         = 4'h7,
