                    rd_busy <= 1'b1;
                    app_cmd <= 3'b001;
                    app_en <= 1'b1;
                    app_addr <= app_addr_r;
                    if (app_rdy && app_en) begin
                        app_addr_r <= app_addr_r + 29'd8;
                        cnt_cmd <= cnt_cmd + 20'd1;
                    end
                end
                READ: begin
                    app_en <= 1'b0;
                    if (app_rd_data_vld) begin
                        cnt_data <= cnt_data + 7'd1;
                        if (cnt_data == BURST_LEN) begin
