    end
  end

  always @(posedge clk_core) begin
    r_wr_sys   <= i_wr_sys;
    r_adrs_sys <= i_adrs_sys;
    r_be_sys   <= i_be_sys;
    r_dbw_sys  <= i_dbw_sys;
    r_adrs_dma <= i_adrs_dma;
    r_dbw_dma  <= i_dbw_dma;
