    input tracemem_tw;
    input [6:0] trc_im_addr;
    input trc_on;
    input trc_wrap;
    input trigbrktype;
    input trigger_state_1;

    wire [37:0] sr;
    wire [1:0] vji_ir_in;
    wire [1:0] vji_ir_out;
