module autovcoder_026213 (
    // Inputs
    CLOCK_50,
    KEY,

    AUD_ADCDAT,

    // Bidirectionals
    AUD_BCLK,
    AUD_ADCLRCK,
    AUD_DACLRCK,

    FPGA_I2C_SDAT,

    // Outputs
    AUD_XCK,
