    input CLK;
    input CLR;
    output CEO;
    output Q0;
    output Q1;
    output Q2;
    output Q3;
    output TC;

    reg Q0_DUMMY = 1'b0;
    reg Q1_DUMMY = 1'b0;
    reg Q2_DUMMY = 1'b0;
    reg Q3_DUMMY = 1'b0;
    wire TC_DUMMY;

    wire XLXN_1 = 1'b1;
    wire XLXN_2 = 1'b1;
    wire XLXN_3;
    wire XLXN_4;
    wire XLXN_5;
    wire XLXN_6;
    wire XLXN_7;
    wire XLXN_8;
    wire XLXN_9;

