    assign Q1 = Q1_DUMMY;
    assign Q2 = Q2_DUMMY;
    assign Q3 = Q3_DUMMY;
    assign TC = TC_DUMMY;

    always @(posedge CLK or posedge CLR) begin
        if (CLR) begin
            Q0_DUMMY <= 1'b0;
        end else if (CE) begin
            if (!XLXN_2) begin
                if (XLXN_1) begin
                    Q0_DUMMY <= 1'b0;
                end
            end else begin
                if (!XLXN_1) begin
                    Q0_DUMMY <= 1'b1;
                end else begin
                    Q0_DUMMY <= !Q0_DUMMY;
                end
            end
        end
    end

    always @(posedge CLK or posedge CLR) begin
        if (CLR) begin
            Q1_DUMMY <= 1'b0;
        end else if (CE) begin
            if (!XLXN_3) begin
                if (Q0_DUMMY) begin
                    Q1_DUMMY <= 1'b0;
                end
            end else begin
                if (!Q0_DUMMY) begin
                    Q1_DUMMY <= 1'b1;
                end else begin
                    Q1_DUMMY <= !Q1_DUMMY;
                end
            end
        end
    end

    always @(posedge CLK or posedge CLR) begin
        if (CLR) begin
            Q2_DUMMY <= 1'b0;
        end else if (CE) begin
            if (!XLXN_6) begin
                if (XLXN_5) begin
                    Q2_DUMMY <= 1'b0;
                end
            end else begin
                if (!XLXN_5) begin
                    Q2_DUMMY <= 1'b1;
                end else begin
                    Q2_DUMMY <= !Q2_DUMMY;
                end
            end
        end
    end

