            if (!XLXN_7) begin
                if (Q0_DUMMY) begin
                    Q3_DUMMY <= 1'b0;
                end
            end else begin
                if (!Q0_DUMMY) begin
                    Q3_DUMMY <= 1'b1;
                end else begin
                    Q3_DUMMY <= !Q3_DUMMY;
                end
            end
        end
    end

