module origen_119988 (
    inout wire sda,
    inout wire scl,
    input wire rst
);

parameter i2c_delay = 5; // Configurable delay for I2C timing

reg sda_oe, scl_oe;
reg sda_o, scl_o;

assign sda = sda_oe ? sda_o : 1'bz;
assign scl = scl_oe ? scl_o : 1'bz;

task automatic start_bit;
    begin
        sda_oe = 1; sda_o = 1;
        scl_oe = 1; scl_o = 1;
        #(i2c_delay);
        sda_o = 0;
        #(i2c_delay);
        scl_o = 0;
    end
