    assign m_axi_awlen = burst_count;
    assign m_axi_awsize = 3'b011; // 8 bytes
    assign m_axi_awburst = 2'b01; // INCR
    assign m_axi_awprot = 3'b000;
    assign m_axi_awcache = 4'b0011;

    // AXI4 Write Data Channel
    assign m_axi_wvalid = (state == WRITE_DATA) && fifo_valid;
    assign m_axi_wdata = fifo_data;
    assign m_axi_wstrb = (burst_count == 0) ? ((1 << last_beat_bytes) - 1) : 8'hFF;
    assign m_axi_wlast = (burst_count == 0);

    // AXI4 Write Response Channel
    assign m_axi_bready = (state == WRITE_RESP);

    // Response interface
    assign response_valid = (state == WRITE_RESP) && m_axi_bvalid;
    assign response_resp = m_axi_bresp;
    assign response_resp_eot = eot;

    // State machine
    always @(posedge m_axi_aclk or negedge m_axi_aresetn) begin
        if (!m_axi_aresetn) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (req_valid && enabled) begin
                    next_state = WRITE_ADDR;
                end
            end
            WRITE_ADDR: begin
                if (m_axi_awready) begin
                    next_state = WRITE_DATA;
                end
            end
            WRITE_DATA: begin
                if (m_axi_wready && m_axi_wvalid && m_axi_wlast) begin
                    next_state = WRITE_RESP;
                end
            end
            WRITE_RESP: begin
                if (m_axi_bvalid && m_axi_bready) begin
                    next_state = IDLE;
                end
            end
        endcase
    end

    // Control and data path logic
    always @(posedge m_axi_aclk or negedge m_axi_aresetn) begin
        if (!m_axi_aresetn) begin
            current_address <= 32'h0;
            burst_count <= 8'h0;
            last_beat_bytes <= 3'h0;
            eot <= 1'b0;
            current_id <= 4'h0;
        end else begin
            case (state)
                IDLE: begin
                    if (req_valid && enabled) begin
                        current_address <= req_address;
                        burst_count <= req_last_burst_length;
                        last_beat_bytes <= req_last_beat_bytes;
                        eot <= 1'b1;
                        current_id <= current_id + 1;
                    end
                end
                WRITE_DATA: begin
                    if (m_axi_wready && m_axi_wvalid) begin
                        current_address <= current_address + 8;
                        if (burst_count > 0) begin
                            burst_count <= burst_count - 1;
                        end
                    end
                end
                WRITE_RESP: begin
                    if (m_axi_bvalid && m_axi_bready) begin
                        eot <= 1'b0;
                    end
                end
            endcase
        end
    end

endmodule

files.conformal_rtl_origen_134248.do:
// Conformal LEC RTL vs RTL: combinational equivalence (no netlist, no technology library).
// Golden and revised in ./rtl/golden.v, ./rtl/revised.v.
// Uses -SystemVerilog for SV support (logic, always_comb, int, $bits, etc); backward compatible with Verilog.
// NOTE: Conformal uses // for comments. Do NOT use # (Conformal treats # as a command and aborts).

set undefined cell black_box
read design ./rtl/golden.v -SystemVerilog -Golden
read design ./rtl/revised.v -SystemVerilog -Revised

// Switch to LEC mode and compare
set system mode lec
add compared points -all
compare
exit -force

