module origen_135738 #(
    parameter N = 16,  // Input sample bit width
    parameter M = 16,  // Output sample bit width
    parameter FS = 100000000,  // Sampling frequency (Hz)
    parameter FC = 10000000,   // Center frequency (Hz)
    parameter BW = 1000000     // Bandwidth (Hz)
) (
    input wire clk,
    input wire rst,
    input wire [N-1:0] in_real,
    input wire [N-1:0] in_imag,
    output reg [M-1:0] out_real,
    output reg [M-1:0] out_imag
);

    // Local parameters
    localparam PHASE_WIDTH = 32;
    localparam PHASE_INCR = $rtoi((2.0**PHASE_WIDTH) * FC / FS);

    // NCO for down-conversion
    reg [PHASE_WIDTH-1:0] phase;
    wire signed [17:0] sin, cos;

    always @(posedge clk or posedge rst) begin
        if (rst)
            phase <= 0;
        else
            phase <= phase + PHASE_INCR;
