    reg [5:0] pos;
    reg [5:0] addr;
    reg [15:0][15:0] buffer;
    reg clk_16Hz;
    reg [31:0] clk_16Hz_count;

    // Clock divider for 16 Hz clock
    always @(posedge clk) begin
        if (clk_16Hz_count == 32'd3125000) begin // Assuming 50 MHz main clock
            clk_16Hz_count <= 32'd0;
            clk_16Hz <= ~clk_16Hz;
        end else begin
            clk_16Hz_count <= clk_16Hz_count + 1;
        end
    end

    // Update scroll position
    always @(posedge clk_16Hz) begin
        if (pos == 6'd63)
            pos <= 6'd0;
        else
            pos <= pos + 1;
    end

    // Buffer management
    always @(posedge clk) begin
        addr_counter <= addr_counter + 1;
        addr <= addr + 1;
        buffer[addr_counter] <= i_row;

        if (addr_counter == 4'd15) begin
            addr_counter <= 4'd0;
            addr <= pos;
        end
    end

    // Output assignments
    assign o_buffer = {buffer[15], buffer[14], buffer[13], buffer[12],
                       buffer[11], buffer[10], buffer[9],  buffer[8],
                       buffer[7],  buffer[6],  buffer[5],  buffer[4],
                       buffer[3],  buffer[2],  buffer[1],  buffer[0]};

    always @(posedge clk) begin
        o_addr <= addr;
    end

