        last_change <= change;
        last_on <= on;
        last_start <= start;
        last_alert <= alert;
        last_state <= state;
    end

    always @(*) begin
        if (off || state == 2'b00) begin
            alarm = 0;
        end else if (beg) begin
            alarm = 1;
        end else begin
            alarm = 0;
        end
        show_beg = beg;
    end

