    if (rst) begin
      main_rin  <= 69'd0;
      main_rout <= 69'd0;
      sub_rin   <= 69'd0;
      sub_rout  <= 69'd0;
    end else begin
      main_rin <= main_rcn_in;
      main_rout <= (sub_2_main && !no_cross) ? sub_rin :
                         (main_2_sub && !no_cross) ? 69'd0 : main_rin;

      sub_rin <= sub_rcn_in;
      sub_rout <= (main_2_sub && !no_cross) ? main_rin :
                        (sub_2_main && !no_cross) ? 69'd0 : sub_rin;
    end

