        FreqCalStatus_next = CAL_STATUS_IDLE;
        ADF_R0_regNext = FreqintReg_next | FreqfracReg_next;
        Done_regNext = 1;
      end

      default: begin
        FreqCalStatus_next = CAL_STATUS_IDLE;
      end


    endcase

  end

endmodule

