module adder_subtractor(
    input wire clk,
    input wire rst,
    input wire [7:0] a,
    input wire [7:0] b,
    input wire add_sub,
    output reg [8:0] result
);

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            result <= 9'b0;
        end else begin
            if (add_sub)
                result <= a + b;
            else
                result <= a - b;
        end
    end

endmodule

module barrel_shifter(
    input wire [3:0] in,
    output wire [3:0] out
);

    wire [1:0] sel;
    wire [3:0] mux_out;

    // Decoder
    assign sel = 2'b01;

    // Multiplexer
    assign mux_out[3] = (sel == 2'b00) ? in[3] :
                        (sel == 2'b01) ? in[2] :
                        (sel == 2'b10) ? in[1] : in[0];
    assign mux_out[2] = (sel == 2'b00) ? in[2] :
                        (sel == 2'b01) ? in[1] :
                        (sel == 2'b10) ? in[0] : in[3];
    assign mux_out[1] = (sel == 2'b00) ? in[1] :
                        (sel == 2'b01) ? in[0] :
                        (sel == 2'b10) ? in[3] : in[2];
    assign mux_out[0] = (sel == 2'b00) ? in[0] :
                        (sel == 2'b01) ? in[3] :
                        (sel == 2'b10) ? in[2] : in[1];

    assign out = mux_out;

endmodule

